	}
}

func TestEmbeddedOpenAPISpecMatchesDocument(t *testing.T) {
	specPath := filepath.Join("docs", "openapi.yaml")

	specBytes, err := os.ReadFile(specPath)
	if err != nil {
		t.Fatalf("read OpenAPI document (%s): %v", specPath, err)
	}

